import React from 'react';

function SensorStatus({ sensorData }) {
  const sensors = [
    { key: 'DS1', name: 'Senzor Vrata 1', icon: '🚪', unit: '' },
    { key: 'DS2', name: 'Senzor Vrata 2', icon: '🚪', unit: '' },
    { key: 'DUS1', name: 'Distanca 1', icon: '📏', unit: 'cm' },
    { key: 'DUS2', name: 'Distanca 2', icon: '📏', unit: 'cm' },
    { key: 'DPIR1', name: 'Pokret 1', icon: '👁️', unit: '' },
    { key: 'DPIR2', name: 'Pokret 2', icon: '👁️', unit: '' },
    { key: 'DPIR3', name: 'Pokret Dnevna', icon: '👁️', unit: '' },
    { key: 'DHT1', name: 'Temp Spavaća', icon: '🌡️', unit: '°C' },
    { key: 'DHT2', name: 'Temp Glavna Spavaća', icon: '🌡️', unit: '°C' },
    { key: 'DHT3', name: 'Temp Kuhinja', icon: '🌡️', unit: '°C' },
    { key: 'GSG', name: 'Žiroskop', icon: '🔄', unit: '' },
    { key: 'DL', name: 'LED Vrata', icon: '💡', unit: '' },
    { key: 'DB', name: 'Buzzer', icon: '🔔', unit: '' },
    { key: 'BRGB', name: 'RGB Sijalica', icon: '🌈', unit: '' },
  ];

  const getValue = (key) => {
    if (sensorData && sensorData[key] !== undefined) {
      return sensorData[key];
    }
    return '-';
  };

  return (
    <div className="panel" style={{ width: '100%' }}>
      <h3>📡 Trenutno Stanje Senzora</h3>

      <div className="sensor-grid">
        {sensors.map((sensor) => (
          <div key={sensor.key} className="sensor-card">
            <div style={{ fontSize: '2rem' }}>{sensor.icon}</div>
            <div className="value">
              {getValue(sensor.key)}{sensor.unit && ` ${sensor.unit}`}
            </div>
            <div className="label">{sensor.name}</div>
            <div style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.5)' }}>
              ({sensor.key})
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default SensorStatus;
